var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"본부, 관측소에 도착했다! 현 시간부로 작전을 개시한다!","JPN":"本部、観測所に到着した！　現時刻をもって作戦を開始する！","ENG":"HQ, we've arrived at the observation post. Commencing operation now.","TWN":"總部，到達觀測站！現在開始作戰！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"3소대는 관측소 밖에서 경계 태세로, 1소대와 2소대는 각각 지상과 지하시설을 수색한다!","JPN":"第3小隊は観測所の外で警戒態勢を、第1小隊と第2小隊はそれぞれ地上と地下施設を捜索せよ！","ENG":"Squad 3, be on guard outside the post. Squad 1 and 2, search the ground and underground facilities respectively.","TWN":"3小隊在觀測站外保持警戒，1小隊和2小隊分別搜索地上和地下設施。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"관측소 대원들의 신변 확보가 최우선이다! 어서 움직여!","JPN":"観測所の隊員たちの身柄確保が最優先だ！　早く行け！","ENG":"Securing the safety of Observation Post personnel is your top priority. Move, move!","TWN":"最優先確保觀測站隊員的人身安全！快行動！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정말이군...... 미량이긴 해도 허수 에너지가 남아 있어.","JPN":"本当だ……微量ではあるが、ノイズエネルギーが残っているな。","ENG":"It's true. The Imaginary Energy still remains, although at a very low level.","TWN":"真的啊……雖說只有微量，但殘留著虛數能量。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정말로 학회장이 바뀌기라도 한 건가? 아니면......","JPN":"本当に学会長が替わったのか？　それとも……","ENG":"Has the President of the Society really changed? Or...","TWN":"學會長真的換人了？還是說……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님, 관측소 직원들은 대부분 사망한 것 같습니다.","JPN":"観測所の職員はほとんど死亡したようです。","ENG":"Sir, I'm afraid there's no survivors among the personnel.","TWN":"要員，我想大部分的觀測站隊員都死亡了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"시신들의 상태는 어떤가?","JPN":"死体の状態は？","ENG":"What were the deceased like?","TWN":"遺體的狀況如何？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"외상은 없는데 다들 잔뜩 겁에 질린 표정이더군요.","JPN":"外傷はありませんが、皆かなり怯えた表情をしていますね。","ENG":"There were no external injuries, but they all looked frightened.","TWN":"沒有外傷，但是他們都露出了極度驚恐的表情。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"꼭...... 공포 영화에나 나올 법한 상황 같습니다.","JPN":"まるで……ホラー映画にでも出てきそうな状況です。","ENG":"It was like... a scene in a horror movie.","TWN":"就像……恐怖電影裡的場景一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님? 괜찮으십니까?","JPN":"大丈夫ですか？","ENG":"Sir, are you all right?","TWN":"要員？您沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 미안하네. 생각할 게 좀 있어서 말일세.","JPN":"ああ、すまない。ちょっと考え事をしていたんだ。","ENG":"Ah, I'm sorry. I was lost in thought.","TWN":"啊，抱歉。我想了些事情。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"여기 오신 뒤로 그 낡은 계산기만 들여다보시는군요. 어디에 쓰는 물건입니까?","JPN":"ここに来てから、その古い計算機ばかり見ていますね。何に使う物なんですか？","ENG":"You've been looking at that old calculator the whole time. May I ask what it is for?","TWN":"來到這裡之後，您就一直在看那個破舊的計算機，這是用在什麼地方的東西啊？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네가 몰라도 되는 특수한 에너지를 포착하는 아티팩트지.","JPN":"君は知る必要のない、特殊なエネルギーを捉えるためのアーティファクトだ。","ENG":"It's an artifact that detects special energy, which you don't need to know about.","TWN":"你不知道也無所謂，這是種捕捉特殊能量的人造神器。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 작전은 중단일세. 당장 철수 준비하게.","JPN":"それから、作戦は中断しろ。すぐに撤収の準備を始めるんだ。","ENG":"And this operation is over. Prepare to evacuate immediately.","TWN":"另外，作戰終止。立刻準備撤退。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"네? 갑자기 무슨 말씀이십니까?","JPN":"え？　突然どういうことですか？","ENG":"Say that again, sir?","TWN":"咦？您突然說些什麼呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"아직 모든 직원들의 생사를 확인한 건 아닙니다. 이대로는......","JPN":"まだ全ての職員の生死を確認したわけではありません。このままでは……","ENG":"We haven't checked all the areas. We can't leave like—huh?","TWN":"我們還沒有確認所有作業員的生死，這樣下去……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"총성......? 지하에서 들려온 건가?","JPN":"銃声……？　地下からか？","ENG":"That sounded like gunfire. Was it from the basement?","TWN":"槍聲……？是地下傳來的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"2 소대, 적을 발견했나! 응답하라! 2소대!","JPN":"第2小隊、敵を発見したのか！　応答せよ！　第2小隊！","ENG":"Squad 2, have you encountered the enemy? Come in, Squad 2!","TWN":"2小隊，發現敵人了嗎！快回答！2小隊！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"......이런, 덫에 걸린 모양이군.","JPN":"……クッ、罠にかかってしまったようだな。","ENG":"No, this must be a trap.","TWN":"……該死，看來是中陷阱了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"네? 무슨 말씀이시죠?","JPN":"え？　どういうことですか？","ENG":"Sorry? What are you saying?","TWN":"什麼？您在說什麼啊？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자기 눈으로 직접 확인하는 게 좋겠지. 저길 보게.","JPN":"自分の目で直接確認した方がいい。向こうを見てみろ。","ENG":"You'd better see for yourself. Over there.","TWN":"你用自己的眼睛直接確認吧，看那邊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"2 소대잖아......?","JPN":"あれは……第2小隊？","ENG":"That's Squad 2!","TWN":"那不是2小隊嗎……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"방금 총성은 뭔가? 왜 통신에 응답하지 않았지!","JPN":"今の銃声は何事だ？　なぜ通信に応じなかった！","ENG":"What was that gunfire? Why didn't you respond, Squad 2?","TWN":"剛才聽到的槍聲是什麼？為什麼不回應通信！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"묻는 말에 대답 못하겠나! 명령에 불복종 하는 건가?","JPN":"質問に応えよ！　命令に従わないつもりか？","ENG":"Answer the question! Do you want to be punished for disobedience?","TWN":"還不回答問題！是要違抗命令嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요, 요원님......?!","JPN":"な、何を……！？","ENG":"S-Sir!","TWN":"要、要員……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 짓입니까?! 아군을 쏘다니요!","JPN":"どういうことですか！？　味方を撃つなんて！","ENG":"What are you doing? You shot an ally!","TWN":"您在做什麼？！竟然對自己人開槍！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"헬멧을 벗겨 줬을 뿐이야. 흥분하지 말고 잘 보게나.","JPN":"ヘルメットを脱がしてやっただけだ。興奮しないでよく見ろ。","ENG":"I just shot the helmet off. Calm yourself and just look.","TWN":"我只是幫他們脫個頭盔而已，別這麼激動，看仔細點。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"저...... 저 꿈틀거리는 게 강화복 안에 들어 있었다는 겁니까?","JPN":"あ……あのグニャグニャしたものが強化服の中に入っていたんですか？","ENG":"What the... Did that wriggling thing come out from the power suit?","TWN":"那個……那個蠕動的東西是進到強化服裡面去了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼...... 대원들은......","JPN":"つまり……隊員たちは……","ENG":"Then they're...","TWN":"那……隊員們……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자세히 설명하기엔 시간이 없으니 요점만 정리해 주겠네.","JPN":"詳しく説明する暇はない、要点だけ整理してやろう。","ENG":"There's no time for explanation, so I'll get straight to the point.","TWN":"沒時間詳細解釋了，我就簡單說一下重點吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"저게 바로 우리의 적일세. 마음 굳게 먹게.","JPN":"あれこそが我らの敵だ。気を強く持て。","ENG":"Those are our enemies. Brace yourself.","TWN":"那就是我們的敵人了，繃緊神經來吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};